// モック用ファイル

// ログイン用モック
export const mockLogin = async ({ userId, password }) => {
	if (userId === 'test' && password === '1234') {
		return {
			success: true,
			user: {
				userName: 'テストユーザ',
				userId: 'test',
				password: '1234',
				role: '主任',
				name: '山田太郎',
				team: '開発A'
			}
		}
	} else {
		return { success: false }
	}
}
